#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin — Created: 2026-04-27
# /ork:emulate-seed --auto — scan package.json, suggest emulators, emit emulate.config.yaml
#
# Reads:  references/dep-to-emulator-map.json (mapping table)
#         <project>/package.json              (deps to scan)
# Writes: <project>/emulate.config.yaml       (only with --apply; otherwise stdout-only)
#
# Exit codes: 0 = at least one mapping or no deps to suggest, 1 = error reading inputs.
# Modes:
#   (default)   report mappings on stdout, do nothing else
#   --apply     write emulate.config.yaml (refuses to overwrite without --force)
#   --force     allow overwriting existing emulate.config.yaml
#   --json      emit machine-readable JSON instead of human report

set -euo pipefail

PROJECT_DIR="${CLAUDE_PROJECT_DIR:-$(pwd)}"
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
MAP_FILE="${SCRIPT_DIR}/../references/dep-to-emulator-map.json"
PKG_FILE="${PROJECT_DIR}/package.json"
OUT_FILE="${PROJECT_DIR}/emulate.config.yaml"

APPLY=0
FORCE=0
JSON_MODE=0
for arg in "$@"; do
  case "${arg}" in
    --apply) APPLY=1 ;;
    --force) FORCE=1 ;;
    --json)  JSON_MODE=1 ;;
    *) printf 'Unknown flag: %s\n' "${arg}" >&2; exit 2 ;;
  esac
done

require() {
  command -v "$1" >/dev/null 2>&1 || { printf '✗ %s not found\n' "$1" >&2; exit 1; }
}
require jq

[[ -f "${PKG_FILE}" ]] || { printf '✗ %s not found\n' "${PKG_FILE}" >&2; exit 1; }
[[ -f "${MAP_FILE}" ]] || { printf '✗ mapping file missing: %s\n' "${MAP_FILE}" >&2; exit 1; }

# 1) Collect declared deps from package.json (dependencies + devDependencies).
deps_json=$(jq -r '
  ((.dependencies // {}) + (.devDependencies // {})) | keys[]
' "${PKG_FILE}" | jq -R . | jq -s .)

# 2) Walk the mapping table; collect matched mappings.
matched_json=$(jq -n \
  --argjson deps "${deps_json}" \
  --slurpfile map "${MAP_FILE}" \
  '
  $map[0].mappings as $maps
  | [
      $maps[]
      | . as $m
      | (.deps | map(select(. as $d | $deps | index($d))) ) as $hits
      | select($hits | length > 0)
      | { matched: $hits,
          emulators: .emulators,
          note: (.note // null) }
    ]
  ')

# 3) Union of all emulator service names (preserve order, dedup).
emulators_json=$(printf '%s' "${matched_json}" | jq '[.[] | .emulators[]] | unique')

# 4) Output
if [[ ${JSON_MODE} -eq 1 ]]; then
  jq -n \
    --argjson matched   "${matched_json}" \
    --argjson emulators "${emulators_json}" \
    --arg     pkg       "${PKG_FILE}" \
    '{ packageJson: $pkg, matched: $matched, emulators: $emulators }'
else
  printf '/ork:emulate-seed --auto — scanning %s\n\n' "${PKG_FILE}" >&2
  matched_count=$(printf '%s' "${matched_json}" | jq 'length')
  if [[ "${matched_count}" -eq 0 ]]; then
    printf 'No mapped dependencies found.\n' >&2
  else
    printf 'Detected:\n' >&2
    printf '%s\n' "${matched_json}" | jq -r '
      .[] | "  " + (.matched | join(", ")) +
            "  →  " + (.emulators | join(", ")) +
            (if .note then " · " + .note else "" end)
    ' >&2
    printf '\nUnion: %s\n' "$(printf '%s' "${emulators_json}" | jq -r 'join(", ")')" >&2
  fi
fi

# 5) Apply mode — write emulate.config.yaml.
if [[ ${APPLY} -eq 1 ]]; then
  emulator_count=$(printf '%s' "${emulators_json}" | jq 'length')
  if [[ "${emulator_count}" -eq 0 ]]; then
    printf '\nNothing to write — no emulators matched.\n' >&2
    exit 0
  fi

  if [[ -f "${OUT_FILE}" && ${FORCE} -ne 1 ]]; then
    printf '\n✗ %s already exists. Re-run with --force to overwrite.\n' "${OUT_FILE}" >&2
    exit 1
  fi

  # Generate YAML — simple top-level `services:` map keyed by emulator name.
  # Each service gets an empty body (emulate uses defaults). Users can edit afterwards.
  tmp="${OUT_FILE}.tmp"
  {
    printf '# Generated by /ork:emulate-seed --auto on %s\n' "$(date -u +%Y-%m-%dT%H:%M:%SZ)"
    printf '# Source: %s\n\n' "${PKG_FILE}"
    printf 'services:\n'
    printf '%s\n' "${emulators_json}" | jq -r '.[]' | while IFS= read -r svc; do
      [[ -z "${svc}" ]] && continue
      printf '  %s: {}\n' "${svc}"
    done
  } > "${tmp}"
  mv "${tmp}" "${OUT_FILE}"
  printf '\n✓ Wrote %s with %s service(s)\n' "${OUT_FILE}" "${emulator_count}" >&2
fi
